import { beforeEach, describe, expect, it, vi } from 'vitest';
import { clearWorkspacePipelineCache } from '../../../../src/extension/pipeline/analysis/state';
import { saveWorkspaceAnalysisDatabaseCache } from '../../../../src/extension/pipeline/database/cache.ts';
import {
  clearWorkspacePipelineStoredCache,
  persistWorkspacePipelineCache,
} from '../../../../src/extension/pipeline/service/cachePersistence';

vi.mock('../../../../src/extension/pipeline/analysis/state', () => ({
  clearWorkspacePipelineCache: vi.fn(),
}));

vi.mock('../../../../src/extension/pipeline/database/cache.ts', () => ({
  saveWorkspaceAnalysisDatabaseCache: vi.fn(),
}));

describe('pipeline/service/cachePersistence', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('delegates cache clearing to the shared workspace cache helper', () => {
    const cache = { files: {} };
    vi.mocked(clearWorkspacePipelineCache).mockReturnValue(cache as never);
    const logInfo = vi.fn();

    expect(clearWorkspacePipelineStoredCache('/workspace', logInfo)).toBe(cache);
    expect(clearWorkspacePipelineCache).toHaveBeenCalledWith('/workspace', logInfo);
  });

  it('skips cache persistence when no workspace root is available', () => {
    const warn = vi.fn();

    persistWorkspacePipelineCache(undefined, { files: {} } as never, warn);

    expect(saveWorkspaceAnalysisDatabaseCache).not.toHaveBeenCalled();
    expect(warn).not.toHaveBeenCalled();
  });

  it('persists the repo-local cache when a workspace root is available', () => {
    const cache = { files: { 'src/a.ts': {} } };
    const warn = vi.fn();

    persistWorkspacePipelineCache('/workspace', cache as never, warn);

    expect(saveWorkspaceAnalysisDatabaseCache).toHaveBeenCalledWith('/workspace', cache);
    expect(warn).not.toHaveBeenCalled();
  });

  it('warns when saving the repo-local cache throws', () => {
    const cache = { files: {} };
    const warn = vi.fn();
    const error = new Error('save failed');
    vi.mocked(saveWorkspaceAnalysisDatabaseCache).mockImplementation(() => {
      throw error;
    });

    persistWorkspacePipelineCache('/workspace', cache as never, warn);

    expect(warn).toHaveBeenCalledWith(
      '[CodeGraphy] Failed to persist repo-local analysis cache.',
      error,
    );
  });
});

import { describe, expect, it, vi } from 'vitest';
import { createSnapshotRelationEntry } from '../../../../src/extension/pipeline/database/cacheRelationEntry';
import * as cacheRowValues from '../../../../src/extension/pipeline/database/cacheRowValues';

describe('pipeline/database/cacheRelationEntry', () => {
  it.each([
    ['filePath', '', 'import', 'source', 'src/from.ts'],
    ['kind', 'src/file.ts', '', 'source', 'src/from.ts'],
    ['sourceId', 'src/file.ts', 'import', '', 'src/from.ts'],
    ['fromFilePath', 'src/file.ts', 'import', 'source', ''],
  ])('returns undefined when the required %s field is missing', (_label, filePath, kind, sourceId, fromFilePath) => {
    const readRequiredString = vi.spyOn(cacheRowValues, 'readRequiredString');

    readRequiredString
      .mockReturnValueOnce(filePath)
      .mockReturnValueOnce(kind)
      .mockReturnValueOnce(sourceId)
      .mockReturnValueOnce(fromFilePath);

    expect(
      createSnapshotRelationEntry({
        filePath,
        kind,
        sourceId,
        fromFilePath,
      } as never),
    ).toBeUndefined();
  });

  it('builds a relation entry from required and optional row values', () => {
    expect(
      createSnapshotRelationEntry({
        filePath: 'src/file.ts',
        kind: 'import',
        sourceId: 'source',
        fromFilePath: 'src/from.ts',
        pluginId: 'plugin.typescript',
        toFilePath: 'src/to.ts',
        fromNodeId: 'from-node',
        toNodeId: 'to-node',
        fromSymbolId: 'from-symbol',
        toSymbolId: 'to-symbol',
        specifier: './to',
        relationType: 'static',
        variant: 'named',
        resolvedPath: '/workspace/src/to.ts',
        metadataJson: '{"weight":2}',
      } as never),
    ).toEqual({
      kind: 'import',
      pluginId: 'plugin.typescript',
      sourceId: 'source',
      fromFilePath: 'src/from.ts',
      toFilePath: 'src/to.ts',
      fromNodeId: 'from-node',
      toNodeId: 'to-node',
      fromSymbolId: 'from-symbol',
      toSymbolId: 'to-symbol',
      specifier: './to',
      type: 'static',
      variant: 'named',
      resolvedPath: '/workspace/src/to.ts',
      metadata: { weight: 2 },
    });
  });
});

